module test ();
    logic bit_0;
    logic bit_1;
    logic bit_2;
    logic bit_3;
    logic [7:0] vector_0;

    always_comb begin
        if (bit_0) begin
            bit_1 = 1;
        end
    end

    always_comb begin
        unique case (vector_0)
            8'b00000001: begin
                if (bit_0) begin
                    bit_2 = 1;
                end
            end
            default: begin
                bit_2 = 0;
            end
        endcase
    end

    always_comb begin
        unique case (vector_0)
            8'b00000001: begin
                if (bit_0) begin
                    bit_3 = 1;
                end else begin
                    bit_3 = 0;
                end
            end
            default: begin
                bit_3 = 0;
            end
        endcase
    end
endmodule
